const { execSync } = require('child_process');

const data = $input.first().json;
const previousRuns = (data.body || []).slice(0, 5);


const topics = previousRuns.map(r => ({ query: r.query, lastRun: r.started_at, runId: r.run_id }));
const results = [];

for (const topic of topics.slice(0, 3)) {
  try {
    const encodedQuery = encodeURIComponent(topic.query);
    const braveKey = $env.BRAVE_SEARCH_API_KEY || $env.BRAVE_API_KEY || '';
    if (!braveKey) continue;

    const searchResult = execSync(`curl -s -H "X-Subscription-Token: ${braveKey}" "https://api.search.brave.com/res/v1/web/search?q=${encodedQuery}&count=5&freshness=pd"`, {
      encoding: 'utf-8', timeout: 15000
    });
    const braveData = JSON.parse(searchResult);
    const newResults = (braveData.web && braveData.web.results) || [];

    if (newResults.length > 0) {
      results.push({
        query: topic.query,
        new_results: newResults.length,
        top_result: newResults[0].title,
        novelty_score: newResults.length >= 3 ? 0.8 : 0.5
      });
    }
  } catch(e) {}
}

return [{ json: { monitored_topics: topics.length, delta_results: results, has_updates: results.filter(r => r.novelty_score >= 0.7).length > 0 } }];

const { execSync } = require('child_process');

const data = $input.first().json;
if (!data.has_updates) return [{ json: { notified: false } }];


const significant = data.delta_results.filter(r => r.novelty_score >= 0.7);
let message = '\ud83d\udd14 Monitoring Update\n\n';
for (const update of significant) {
  message += `*${update.query}*\n${update.new_results} neue Ergebnisse\nTop: ${update.top_result}\n\n`;
}
message += 'Tipp: Deep-Recherche starten fuer Details.';

try {
  const body = JSON.stringify({ chat_id: Number($env.TELEGRAM_CHAT_ID || ''), text: message, parse_mode: 'Markdown' });
  execSync(`curl -s -X POST -H "Content-Type: application/json" -d '${body.replace(/'/g, "'\\''")}'  "https://api.telegram.org/bot${$env.RESEARCH_BOT_TOKEN || ''}/sendMessage"`, {
    encoding: 'utf-8', timeout: 10000
  });
} catch(e) {}

return [{ json: { notified: true, updates: significant.length } }];
